  /**
   * 创建 Bootstrap 容器
   * @param options 容器配置选项
   * @returns 创建的容器元素
   */
  createContainer(options: ElementOptions & { fluid?: boolean } = {}): HTMLElement {
    const { fluid = false, className = [], ...elementOptions } = options;

    const containerClasses = fluid ? ['container-fluid'] : ['container'];
    if (Array.isArray(className)) {
      containerClasses.push(...className);
    } else if (className) {
      containerClasses.push(className);
    }

    return this.createElement({
      ...elementOptions,
      className: containerClasses
    });
  }

  /**
   * 创建 Bootstrap 行
   * @param options 行配置选项
   * @returns 创建的行元素
   */
  createRow(options: ElementOptions = {}): HTMLElement {
    return this.createElement({
      ...options,
      className: ['row', ...(Array.isArray(options.className) ? options.className : options.className ? [options.className] : [])]
    });
  }

