  /**
   * 创建图标元素
   * @param options 图标配置选项
   * @returns 创建的图标 HTMLElement
   */
  createIcon(options: IconOptions): HTMLElement {
    const {
      iconName,
      size,
      color,
      spin = false,
      pulse = false,
      className = [],
      styles = {},
      ...elementOptions
    } = options;

    // 创建图标元素
    const icon = this.createElement({
      tag: 'i',
      className: ['icon', 'iconfont', `icon-${iconName}`, ...(Array.isArray(className) ? className : [className])],
      styles: {
        ...styles,
        ...(color && { color }),
        ...(typeof size === 'number' ? { fontSize: `${size}px` } : {}),
        ...(spin && { animation: 'spin 1s linear infinite' }),
        ...(pulse && { animation: 'pulse 1s ease-in-out infinite' })
      },
      ...elementOptions
    });

    // 添加尺寸类名
    if (typeof size === 'string') {
      icon.classList.add(`icon-${size}`);
    }

    // 添加动画类名
    if (spin) {
      icon.classList.add('icon-spin');
    }
    if (pulse) {
      icon.classList.add('icon-pulse');
    }

    return icon;
  }

