export function initUIEventListener() {
    document.addEventListener('click', function (event) {
        var target = event.target;
        if (!target || !(target as HTMLElement).classList.contains('marble-import-media-delete')) {
            return;
        }
        var item = (target as HTMLElement).closest('.marble-import-media-item');
        if (!item) return;
        var mediaId = item.getAttribute('data-media-id');
        console.log('marble media delete clicked, data-media-id:', mediaId);
        if(modelDialogTools){
            modelDialogTools.deleteMarbleMedia(mediaId ?? '');
        }
    });
}

