class GlobalManager {
    private visionSceneMap: Map<string, visionarySceneInfo>
    private currentSelected: { sceneid: string, objectid: string } // 当前选中Scene、object的信息（id）
    private activePanelTab: string = '';
    private currentChangeCallback: (() => void) | null = null;
    private sceneFS: SceneFS | null = null;
    private injectedGetApp?: () => any;

    constructor() {
        this.visionSceneMap = new Map();
        this.currentSelected = { sceneid: '', objectid: '' };
        this.activePanelTab = 'model'; // 默认激活模型面板
    }

    addSceneView(id: string, visionScene: visionarySceneInfo) {
        this.visionSceneMap.set(id, visionScene)
    }
    removeSceneViewById(id: string) {
        const sceneInfo = this.visionSceneMap.get(id);
        if (sceneInfo) {
            sceneInfo.scene.destroy();

            if (sceneInfo.cameraController) {
                sceneInfo.cameraController.destroy();
            }
            if (sceneInfo.animationController) {
                sceneInfo.animationController.destroy();
            }
            if (sceneInfo.fileController) {
                sceneInfo.fileController.destroy();
            }
            this.visionSceneMap.delete(id);
        }
    }
    getActivePanelTab() {
        return this.activePanelTab;
    }
    setActivePanelTab(tab: string) {
        this.activePanelTab = tab;
        window.dispatchEvent(new CustomEvent('event.panelTabChange', { detail: this.activePanelTab }));
    }
    getAllSceneInfos(): visionarySceneInfo[] {
        return Array.from(this.visionSceneMap.values());
    }

    setCurrentSelected(sceneid: string, objectid: string) {
        this.currentSelected.sceneid = sceneid
        this.currentSelected.objectid = objectid;
        if (this.currentChangeCallback) {
            this.currentChangeCallback();
        }
console.log('[globalManager] setCurrentSelected', this.currentSelected);
        window.dispatchEvent(new CustomEvent('event.modelSelectChange', { detail: this.currentSelected }));
    }

    getCurrentSelected() {
        return this.currentSelected;
    }
    getCurrentSceneView(): VisionaryScene | null {
        const sceneInfo = this.visionSceneMap.get(this.currentSelected.sceneid);
        if (sceneInfo) {
            return sceneInfo.scene;
        }
        return null;
    }
    getCurrentSceneInfo(hasDefault: boolean = false): visionarySceneInfo | null {
        if (this.currentSelected.sceneid != '') {
            const sceneInfo = this.visionSceneMap.get(this.currentSelected.sceneid);
            if (sceneInfo) {
                return sceneInfo;
            }
        }
        if (!hasDefault) {
            return null;
        }
        if (this.visionSceneMap.size > 0) {
            const firstValue = this.visionSceneMap.values().next().value;
            return firstValue ?? null;
        }
        return null;
    }
    getCurrentObject(): VisionaryObject | null {
        const sceneInfo = this.visionSceneMap.get(this.currentSelected.sceneid);
        if (sceneInfo) {
            const obj = sceneInfo.scene.getObjectById(this.currentSelected.objectid);
            return obj ?? null;
        }
        return null;
    }
    getCurrentCamera(): CameraController | null {
        const sceneInfo = this.getCurrentSceneInfo();
        if (sceneInfo) {
            return sceneInfo.cameraController;
        }
        return null;
    }
    getCurrentAnimation(): AnimationController | null {
        const sceneInfo = this.getCurrentSceneInfo();
        if (sceneInfo) {
            return sceneInfo.animationController;
        }
        return null;
    }
    setCurrentChangeCallback(callback: () => void) {
        this.currentChangeCallback = callback;
    }

    getViewWindowIfSingle() {
        const mainAppContainerDom = document.getElementById(globalConfig.domIds.mainAppContainer);
        if (mainAppContainerDom) {
            return !mainAppContainerDom.classList.contains('multi-window-app-container');
        }
        return false;
    }

    openRightToolsBar() {
        const toolContainer = document.getElementById(globalConfig.domIds.rightToolsBar);
        if (toolContainer && !toolContainer.classList.contains('active')) {
            toolContainer.classList.add('active');
            window.dispatchEvent(new Event('resize'));
        }
    }
    closeRightToolsBar() {
        const toolContainer = document.getElementById(globalConfig.domIds.rightToolsBar);
        if (toolContainer&& toolContainer.classList.contains('active')) {
            toolContainer.classList.remove('active');
            window.dispatchEvent(new Event('resize'));
        }
    }

    setSceneFS(sceneFS: SceneFS) {
        this.sceneFS = sceneFS;
    }
    getSceneFS() {
        return this.sceneFS;
    }
    setInjectedGetApp(getApp: () => any) {
        this.injectedGetApp = getApp;
    }
    getAppInstance(): any {
        if (this.injectedGetApp) return this.injectedGetApp();
        return (window as any).getAppForSceneFS ? (window as any).getAppForSceneFS() : null;
    }

}

