
// 获取图片url，用来页面显示
export async function getObjectByImgFile(file: File) {
    let imageBytes = null;
    let url = null;
    if (file && file.type.includes('image')) {
        imageBytes = new Uint8Array(await file.arrayBuffer());
        url = URL.createObjectURL(file);
    }
    console.log('getObjectByImgFile, url:', url);
    return url;
}

export async function getSrcByImgFile(file: File) {
    let result = '';
    if (file) {
        if (file.type.includes('image')) {
            result = URL.createObjectURL(file);
        }
        if (file.type.includes('video')) {
            result=new URL('/images/video-icon.png', import.meta.url).href;
        }
    }
    return result;
}

////////////////////  for marble4api////////////////////////////////////////////////////////////////////////
export function getFileKind(file_name: string) {
    const extension = file_name.split('.').pop() || '';
    if(extension === 'jpg' || extension === 'jpeg' || extension === 'png' || extension === 'webp'){
        return 'image';
    }else if(extension === 'mp4' || extension === 'mov' || extension === 'mkv'){
        return 'video';
    }
    return '';
}
export function getFileName(file_name: string) {
    return file_name.split('.').slice(0, -1).join('.');
}
