    stopAnimation() {
        const sceneInfos = globalManager.getAllSceneInfos();
        if (sceneInfos.length > 0) {
            sceneInfos.forEach(sceneInfo => {
                if (globalConfig.sceneParams.isAnimation && typeof sceneInfo.scene.setGaussianAnimationTime === 'function') {
                    sceneInfo.scene.setGaussianAnimationTime(-1);
                }
            });
        }
    }
