    handleMarbleImportUploadBtnClick(e: Event) {
        e.preventDefault();
        e.stopPropagation();
        console.log('handleMarbleImportUploadBtnClick');
        const fileInputConfig = this.getMarbleMediaInputConfig();
        if (!fileInputConfig.canUpload) {
            this.showMsgDialog(getI18nText('modal.marbleImport.marbleMediaUploadLimit'));
            return;
        }
        const fileInput = document.createElement('input');

        fileInput.type = 'file';
        fileInput.accept = fileInputConfig.accept;
        fileInput.multiple = fileInputConfig.maxUploadCount > 1;
        fileInput.maxLength = fileInputConfig.maxUploadCount;

        fileInput.onchange = async (e) => {
            const files = (e.target as HTMLInputElement).files;
            if (files) {
                if (files.length > fileInputConfig.maxUploadCount) {
                    this.showMsgDialog(getI18nText('modal.marbleImport.marbleMediaUploadLimit'));
                    return;
                }
                for (let index = 0; index < files.length; index++) {
                    const file = files[index];
                    const id = new Date().getTime().toString() + '_' + index;
                    this.marbleImportMediaFiles.push({
                        id: id, // 用时间戳+index
                        file: file,
                        media_asset_id: '',
                        metadata: {},
                        kind: file.type.includes('image') ? 'image' : 'video',
                        extension: file.name.split('.').pop() || '',
                        file_name: file.name,
                        file_src: await getSrcByImgFile(file),
                        azimuth: 0
                        // file_size: file.size,
                    });
                    console.log("[ModelDialogTools] select files----", {
                        id: id,
                        kind: file.type.includes('image') ? 'image' : 'video',
                        extension: file.name.split('.').pop() || '',
                        file_name: file.name
                    });
                }

                this.updateMarbleImportMediaList();
            }
            fileInput.value = '';
        };
        fileInput.click();
    }
