    private async checkMarbleAPIKeyAvailable(formKeyInput: HTMLInputElement, marbleImportConfirm: HTMLButtonElement) {
        const currentRequestId = ++this.marbleKeyCheckRequestId;
        const keyValue = formKeyInput.value.trim();
        const errorTipId = 'marbleImportFormKeyInputErrorTip';
        const invalidKeyText = getI18nText('modal.marbleImport.invalidApiKey');
        const updateKeyInputValidationState = (isValid: boolean) => {
            let errorTipDom = document.getElementById(errorTipId) as HTMLDivElement | null;
            if (isValid) {
                formKeyInput.setCustomValidity('');
                formKeyInput.classList.remove('marble-key-input-invalid');
                if (errorTipDom) {
                    errorTipDom.remove();
                }
                return;
            }

            formKeyInput.setCustomValidity(invalidKeyText);
            formKeyInput.classList.add('marble-key-input-invalid');
            if (!errorTipDom) {
                errorTipDom = document.createElement('div');
                errorTipDom.id = errorTipId;
                errorTipDom.className = 'marble-key-input-error-tip';
                formKeyInput.insertAdjacentElement('afterend', errorTipDom);
            }
            errorTipDom.textContent = invalidKeyText;
        };

        if (!keyValue) {
            marbleImportConfirm.disabled = true;
            updateKeyInputValidationState(false);
            return;
        }

        const isAvailable = await marble4ApiController.checkMarbleKeyAvailable(keyValue);
        if (currentRequestId !== this.marbleKeyCheckRequestId) return;
        console.log("检查checkMarbleKey----Available apiKey是否有效-button disabled--", !isAvailable);
        marbleImportConfirm.disabled = !isAvailable;
        updateKeyInputValidationState(isAvailable);
    }

