    private resolveMarbleImageUrl(rawUrl: string): string {
        if (!rawUrl) return '';
        try {
            const parsedUrl = new URL(rawUrl, window.location.origin);
            const isHttp = parsedUrl.protocol === 'http:' || parsedUrl.protocol === 'https:';
            const isCrossOrigin = parsedUrl.origin !== window.location.origin;
            if (import.meta.env.DEV && isHttp && isCrossOrigin) {
                return `/__marble_cdn_proxy${parsedUrl.pathname}${parsedUrl.search}`;
            }
            return parsedUrl.toString();
        } catch (error) {
            console.warn('[MarbleHistory] invalid image url, use raw value', rawUrl, error);
            return rawUrl;
        }
    }

