    async doUploadMarbleMedia(name: string, textPrompt: string) {
        if (!marble4ApiController) {
            console.error('Marble API controller not initialized');
            throw new Error('Marble API controller not initialized');
        }

        // 高精度模式开启时使用更高质量（更慢）的 Marble 0.1-plus
        const highPrecisionEnabled = (document.getElementById('marbleModelSwitch') as HTMLInputElement | null)?.checked ?? false;
        const draft = !highPrecisionEnabled;

        const mediaInfo = await marble4ApiController.generateMarbleModel(
            name,
            textPrompt,
            this.marbleImportMediaFiles,
            false,
            draft
        );

        return mediaInfo;
    }

    async doSelectFolder(handle: FileSystemDirectoryHandle) {
        const sceneFS = globalManager.getSceneFS();
        if (!sceneFS) {
            console.warn('[Scene] SceneFS 未初始化，无法打开场景');
            this.showMsgDialog(getI18nText('errorinfo.sceneFSNotAvailable'));
            return;
        }
        try {
            console.log('Folder selected:', handle);
            await sceneFS.ensurePermission(handle, 'readwrite');
            // 保存文件夹 handle
            this.sceneSaveModalFolderHandle = handle;
            const saveSceneFolderInput = document.getElementById('saveSceneFolderInput') as HTMLInputElement | null;
            // 在输入框中显示文件夹名称
            if (saveSceneFolderInput) {
                saveSceneFolderInput.value = handle.name;
            }

            console.log('SceneFS: Folder selected for save:', handle.name);
        } catch (error) {
            if ((error as Error).name === 'AbortError') {
                console.log('Folder selection cancelled by user');
            } else {
                console.error('Failed to select folder:', error);
            }
        }
    }

