    public async updateMarbleHistoryList(scene: VisionaryScene | null) {
        if (!scene) {
            console.error('[MarbleHistory] update aborted: scene is null');
            return;
        }
        // 强制在使用前校验并兜底重新查询
        if (!this.marbleHistoryListBodyDom) {
            this.marbleHistoryListBodyDom = document.getElementById('marbleHistoryListBody');
        }
        if (!this.marbleHistoryListBodyDom) {
            console.error('[MarbleHistory] update aborted: #marbleHistoryListBody is null');
            return;
        }
        const listBodyDom = this.marbleHistoryListBodyDom;

        // marbleHistoryListBodyDom
        const marbleModelList = []
        const marbleHistoryFormKeyInput = document.getElementById('marbleHistoryFormKeyInput') as HTMLInputElement | null;
        if (marbleHistoryFormKeyInput && marbleHistoryFormKeyInput.value.trim() !== '') {
            // 查询 Marble 模型列表
            marble4ApiController.setApiKey(marbleHistoryFormKeyInput.value.trim());
            let marbleModelList;
            try {
                marbleModelList = await marble4ApiController.listWorlds({
                    page_size: 5,
                    page_token: this.marbleModelListPageToken
                });
            } catch (error) {
                console.error('[MarbleHistory] listWorlds failed', error);
                if (this.marbleHistoryLoadMoreBtn) {
                    this.marbleHistoryLoadMoreBtn.style.display = 'none';
                }
                this.showMsgDialog(getI18nText('modal.marbleImport.modelListQueryFailed'));
                return;
            }

            this.marbleModelListPageToken = marbleModelList.next_page_token || null;
            let hasNew = false;
            if (marbleModelList && marbleModelList.worlds && marbleModelList.worlds.length > 0) {
                marbleModelList.worlds.forEach(item => {
                    if (item.assets && marble4ApiController.checkMarbleModelAsset(item.assets)) {
                        const modelDom = document.getElementById(`marbleModelItem_${item.world_id}`);
                        if (!modelDom) {
                            const marbleModelInfo: MarbleModelInfo = {
                                id: item.world_id,
                                name: item.display_name,
                                image: item.assets?.thumbnail_url || '',
                                status: 'completed',
                                textPrompt: (item.world_prompt as TextWorldPrompt).text_prompt || '',
                                created_at: item.created_at || '',
                                updated_at: item.updated_at || '',
                                srcurl: item.assets?.splats?.spz_urls?.full_res || '',
                            };
                            const marbleModelItem = this.createMarbleModelItem(marbleModelInfo, scene);
                            listBodyDom.appendChild(marbleModelItem);
                            hasNew = true;
                        }
                    }
                });
            } else {
                console.warn('[MarbleHistory] listWorlds returned empty worlds');
            }
            if ((!hasNew || marbleModelList.worlds.length < 5) && this.marbleHistoryLoadMoreBtn) {
                this.marbleHistoryLoadMoreBtn.style.display = 'none';
            }
        } else {
            console.warn('[MarbleHistory] form key is empty, skip list query');
        }
    }

