    public showConfirmDialog(
        title: string,
        message: string,
        onConfirm?: () => void,
        onCancel?: () => void
    ) {
        if (!this.confirmModalDom) {
            console.warn('Confirm modal element not found');
            return;
        }

        this.cleanupConfirmDialogHandlers();

        const titleElement = this.confirmModalDom.querySelector('#modelDeleteConfirmLabel');
        const messageElement = this.confirmModalDom.querySelector('#modelDeleteConfirmMessage');
        const cancelButton = this.confirmModalDom.querySelector('[data-role="cancel"]');
        const confirmButton = this.confirmModalDom.querySelector('[data-role="confirm"]');
        const closeButton = this.confirmModalDom.querySelector('.btn-close');

        if (titleElement) {
            (titleElement as HTMLElement).textContent = title;
        }
        if (messageElement) {
            (messageElement as HTMLElement).textContent = message;
        }

        this.confirmOnCancel = typeof onCancel === 'function' ? onCancel : null;
        this.confirmLastAction = 'dismiss';

        if (cancelButton && this.confirmCancelHandler) {
            cancelButton.removeEventListener('click', this.confirmCancelHandler);
        }
        this.confirmCancelHandler = () => {
            this.confirmLastAction = 'cancel';
            if (typeof onCancel === 'function') {
                onCancel();
            }
            this.closeConfirmDialog();
        };
        if (cancelButton) {
            cancelButton.addEventListener('click', this.confirmCancelHandler);
        }

        if (confirmButton && this.confirmConfirmHandler) {
            confirmButton.removeEventListener('click', this.confirmConfirmHandler);
        }
        this.confirmConfirmHandler = () => {
            this.confirmLastAction = 'confirm';
            if (typeof onConfirm === 'function') {
                onConfirm();
            }
            this.closeConfirmDialog();
        };
        if (confirmButton) {
            confirmButton.addEventListener('click', this.confirmConfirmHandler);
        }

        if (closeButton && this.confirmCloseHandler) {
            closeButton.removeEventListener('click', this.confirmCloseHandler);
        }
        this.confirmCloseHandler = () => {
            this.confirmLastAction = 'cancel';
            if (typeof onCancel === 'function') {
                onCancel();
            }
            this.closeConfirmDialog();
        };
        if (closeButton) {
            closeButton.addEventListener('click', this.confirmCloseHandler);
        }

        if (this.confirmModalDom && this.confirmHiddenHandler) {
            this.confirmModalDom.removeEventListener('hidden.bs.modal', this.confirmHiddenHandler as EventListener);
        }
        this.confirmHiddenHandler = () => {
            if (this.confirmLastAction === 'dismiss' && this.confirmOnCancel) {
                this.confirmOnCancel();
            }
            this.cleanupConfirmDialogHandlers();
        };
        this.confirmModalDom.addEventListener('hidden.bs.modal', this.confirmHiddenHandler as EventListener);

        if (!this.confirmModalInstance && typeof bootstrap !== 'undefined' && bootstrap && typeof bootstrap.Modal === 'function') {
            this.confirmModalInstance = new bootstrap.Modal(this.confirmModalDom);
        }

        if (this.confirmModalInstance && typeof this.confirmModalInstance.show === 'function') {
            this.confirmModalInstance.show();
        } else {
            this.confirmModalDom.classList.add('show', 'vision-modal-show');
            this.confirmModalDom.style.display = 'block';
        }
    }

